import subprocess
from beeai.tools import ShellTool

security_tool = ShellTool(allowed_commands=['bandit', 'safety', 'pip-audit'])

@agent.tool
def scan_security(code: str, requirements: str = None):
    '''Scan code for vulnerabilities and check dependencies'''

    # Bandit static analysis
    bandit_result = security_tool.run(f'bandit -f json -r /tmp/generated_code')

    if requirements:
        safety_result = security_tool.run(f'safety check -r requirements.txt')

    return {
        'bandit_issues': parse_bandit(bandit_result),
        'safety_issues': parse_safety(safety_result),
        'safe_to_apply': no_critical_issues()
    }

async def debug_loop(user_request: str):
    context = await repo_tool.get_context()

    for iteration in range(5):  # max 5 iterations
        code_proposal = await coding_agent.run(f'{user_request}\nContext: {context}')

        scan_result = await scan_security(code_proposal)
        if not scan_result['safe_to_apply']:
            feedback = f"Security issues: {scan_result['bandit_issues']}"
            continue

        exec_result = await exec_tool.run(code_proposal)
        if exec_result.success:
            return {'fixed': True, 'code': code_proposal}

        context += f"Failed: {exec_result.error}\n"

    return {'fixed': False, 'reason': 'Max iterations exceeded'}

