def monitor_memory(event):
    if event['type'] == 'memory_update':
        memory_size = len(event['agent_state']['memory'])

        if memory_size > 75:  # 75% of limit
            # Trigger summarization
            summary = ai_summarize(event['memory'])
            event['agent_state']['memory'] = summary

            vex.record_metric('memory_summarized', {'size_before': memory_size})

        return {'action': 'summarize', 'threshold': 0.75}

