@vex.verification_pipeline('coding_assistant')
def secure_code_pipeline(event):
    verifications = [
        verify_code_correctness(event),
        scan_security_vulnerabilities(event),
        check_credential_leakage(event),
        validate_dependencies(event),
        check_license_compliance(event)
    ]

    results = []
    for verification in verifications:
        result = verification.run(event)
        results.append(result)

        if not result.passed:
            vex.alert(f"Verification failed: {result.name}")
            return {'status': 'blocked', 'failures': results}

    return {'status': 'approved', 'scores': {r.name: r.score for r in results}}
